import os
from datetime import datetime, timedelta
from typing import Optional
import uuid
import json

from fastapi import FastAPI, Depends, HTTPException, status, Request
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from pydantic import BaseModel
import redis.asyncio as redis


# Configuration
REDIS_URL = os.getenv("REDIS_URL", "redis://localhost:6379/0")
TOKEN_EXPIRY_SECONDS = int(os.getenv("TOKEN_EXPIRY_SECONDS", "3600"))

# App initialization
app = FastAPI(title="OAuth 2.0 Protected API Service")

# Redis client
redis_client: Optional[redis.Redis] = None

# Security scheme
security = HTTPBearer()


# Models
class TokenData(BaseModel):
    user_id: str
    scopes: list[str]
    issued_at: str
    expires_at: str


class TokenResponse(BaseModel):
    access_token: str
    token_type: str = "bearer"
    expires_in: int = TOKEN_EXPIRY_SECONDS


class UserResponse(BaseModel):
    user_id: str
    scopes: list[str]
    message: str


class HealthResponse(BaseModel):
    status: str
    redis_connected: bool


# Startup / Shutdown
@app.on_event("startup")
async def startup():
    global redis_client
    redis_client = redis.from_url(REDIS_URL, decode_responses=True)
    try:
        await redis_client.ping()
        print("Connected to Redis successfully.")
    except Exception as e:
        print(f"Warning: Could not connect to Redis: {e}")


@app.on_event("shutdown")
async def shutdown():
    global redis_client
    if redis_client:
        await redis_client.close()


# Helper to get redis client
async def get_redis() -> redis.Redis:
    if redis_client is None:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis connection not available",
        )
    return redis_client


# --- Token Validation Dependency ---

async def validate_oauth_token(
    credentials: HTTPAuthorizationCredentials = Depends(security),
    r: redis.Redis = Depends(get_redis),
) -> TokenData:
    """
    Dependency that extracts the Bearer token from the Authorization header,
    looks it up in Redis, and returns the associated TokenData if valid.
    Raises 401 if the token is missing, invalid, or expired.
    """
    token = credentials.credentials

    if not token:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Bearer token is missing",
            headers={"WWW-Authenticate": "Bearer"},
        )

    # Look up token in Redis
    token_key = f"oauth:token:{token}"
    token_json = await r.get(token_key)

    if token_json is None:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid or expired token",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    try:
        token_data_dict = json.loads(token_json)
        token_data = TokenData(**token_data_dict)
    except (json.JSONDecodeError, ValueError) as e:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail=f"Malformed token data: {e}",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    # Check expiry (belt-and-suspenders; Redis TTL should handle this too)
    expires_at = datetime.fromisoformat(token_data.expires_at)
    if datetime.utcnow() > expires_at:
        # Clean up expired token
        await r.delete(token_key)
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Token has expired",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    return token_data


# --- Scope-checking dependency factory ---

def require_scopes(*required_scopes: str):
    """
    Returns a dependency that checks the validated token has all required scopes.
    """
    async def _check_scopes(
        token_data: TokenData = Depends(validate_oauth_token),
    ) -> TokenData:
        missing = set(required_scopes) - set(token_data.scopes)
        if missing:
            raise HTTPException(
                status_code=status.HTTP_403_FORBIDDEN,
                detail=f"Insufficient scopes. Missing: {missing}",
            )
        return token_data

    return _check_scopes


