@app.get("/health", response_model=HealthResponse)
async def health_check():
    """Public health check endpoint."""
    redis_ok = False
    if redis_client:
        try:
            await redis_client.ping()
            redis_ok = True
        except Exception:
            pass
    return HealthResponse(status="ok", redis_connected=redis_ok)


@app.post("/token", response_model=TokenResponse)
async def create_token(
    user_id: str,
    scopes: str = "read",
    r: redis.Redis = Depends(get_redis),
):
    """
    Development/testing endpoint to issue a token and store it in Redis.
    In production, tokens would be issued by a proper OAuth 2.0 authorization server.
    """
    access_token = str(uuid.uuid4())
    now = datetime.utcnow()
    expires_at = now + timedelta(seconds=TOKEN_EXPIRY_SECONDS)

    token_data = TokenData(
        user_id=user_id,
        scopes=[s.strip() for s in scopes.split(",")],
        issued_at=now.isoformat(),
        expires_at=expires_at.isoformat(),
    )

    token_key = f"oauth:token:{access_token}"
    await r.set(token_key, token_data.json(), ex=TOKEN_EXPIRY_SECONDS)

    return TokenResponse(access_token=access_token, expires_in=TOKEN_EXPIRY_SECONDS)


@app.delete("/token/revoke")
async def revoke_token(
    token_data: TokenData = Depends(validate_oauth_token),
    credentials: HTTPAuthorizationCredentials = Depends(security),
    r: redis.Redis = Depends(get_redis),
):
    """Revoke the current token (requires valid token)."""
    token_key = f"oauth:token:{credentials.credentials}"
    await r.delete(token_key)
    return {"detail": "Token revoked successfully"}


